import React from "react";
import CommonTable from "../../../components/CommonTable";

function SchemeMastersTable({
    module,
    data = [],
    loading = false,
    onEdit
}) {

    const columns = [
        {
            header: "#",
            render: (row, index) => index + 1
        },

        ...module.tableColumns.map(col => ({
            header: col.header,
            render: row => row[col.field] || "-"
        })),

        {
            header: "Status",
            render: row => (
                <span
                    className={`badge ${
                        row.status === "A"
                            ? "bg-success"
                            : "bg-danger"
                    }`}
                >
                    {row.status === "A" ? "Active" : "Inactive"}
                </span>
            )
        },

        {
            header: "Action",
            render: row => (
                <button
                    className="btn btn-sm btn-outline-primary"
                    onClick={() => onEdit(row)}
                >
                    <i className="fa fa-pencil"></i>
                </button>
            )
        }
    ];

    return (
        <div className="card border-0 shadow-sm">
            <div
                className="card-header border-0"
                style={{
                    background: module.bg,
                    borderLeft: `5px solid ${module.color}`
                }}
            >
                <h5 className="card-title mb-0 fw-bold">
                    {module.listTitle}
                </h5>

                <small>
                    All {module.listSubTitle} added to the system.
                </small>
            </div>

            <div
                className="card-body"
                style={{ minHeight: "600px" }}
            >
                {data.length > 0 ? (
                    <CommonTable
                        columns={columns}
                        data={data}
                        loading={loading}
                    />
                ) : (
                    <div className="d-flex justify-content-center text-center pt-5">
                        <div className="text-secondary px-3">
                            <div
                                className="rounded-circle d-inline-flex align-items-center justify-content-center mb-3"
                                style={{
                                    width: "64px",
                                    height: "64px",
                                    background: module.bg
                                }}
                            >
                                <i
                                    className="fa fa-file-text-o fa-2x"
                                    style={{ color: module.color }}
                                ></i>
                            </div>

                            <div className="fw-semibold text-dark mb-1">
                                No {module.listSubTitle} yet
                            </div>

                            <div
                                className="small"
                                style={{ maxWidth: "240px" }}
                            >
                                Use the form on the right to add your first{" "}
                                {module.listSubTitle}.
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

export default SchemeMastersTable;
